      <button
        type="button"
        onClick={onManual}
        className="text-[13px] text-slate-400 hover:text-slate-600 bg-transparent border-0 cursor-pointer p-0 text-left"
      >
        Skip LinkedIn import. I&apos;ll enter my details manually.
      </button>
    </div>
  )
