  const [connectionTexts, setConnectionTexts] = useState<string[]>(
    CONNECTION_TEMPLATES.map(t => t.text)
  )

  useEffect(() => { load() }, [])

  useEffect(() => {
    if (!state?.isPostDay) return
    if (!handoffSummary.trim()) {
      const summarySeed = state.post.draft_text.split('\n').filter(Boolean).slice(0, 2).join(' ')
      setHandoffSummary(summarySeed)
    }
  }, [state, handoffSummary])

  async function load() {
    setLoading(true)
    setError('')
    try {
      const res = await fetch('/api/admin/social/today')
      if (!res.ok) { setError(`Failed to load (${res.status})`); return }
      const data: TodayResponse = await res.json()
      setState(data)
      if (data.isPostDay) {
        setDraftText(data.post.draft_text)
        setNotesText(data.post.notes ?? '')
      }
      await loadHandoffHistory()
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  async function loadHandoffHistory() {
    setHandoffHistoryLoading(true)
    try {
      const res = await fetch('/api/admin/social/handoff-approved')
      if (!res.ok) return
      const data = await res.json() as { runs?: HandoffHistoryRun[] }
      setHandoffHistory(data.runs ?? [])
    } finally {
      setHandoffHistoryLoading(false)
    }
  }

  async function handleSave() {
    if (!state?.isPostDay || saving) return
    setSaving(true)
    try {
      const res = await fetch(`/api/admin/social/${state.post.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ draft_text: draftText }),
      })
      if (!res.ok) { setError('Save failed'); return }
      const data = await res.json() as { post?: SocialPost }
      const updatedPost = data.post
      if (!updatedPost) { setError('Save failed'); return }
      setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
    } finally {
      setSaving(false)
    }
  }

  async function handleNotesSave() {
    if (!state?.isPostDay || savingNotes) return
    setSavingNotes(true)
    try {
      await fetch(`/api/admin/social/${state.post.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notes: notesText }),
      })
      setState(prev => prev?.isPostDay ? { ...prev, post: { ...prev.post, notes: notesText || null } } : prev)
    } finally {
      setSavingNotes(false)
    }
  }

  async function handleCopy() {
    await navigator.clipboard.writeText(draftText)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
    if (state?.isPostDay && draftText !== state.post.draft_text) await handleSave()
  }

  async function handleMarkPosted() {
    if (!state?.isPostDay || markingPosted) return
    setMarkingPosted(true)
    try {
      if (draftText !== state.post.draft_text) await handleSave()
      const res = await fetch(`/api/admin/social/${state.post.id}/mark-posted`, { method: 'POST' })
      if (!res.ok) { setError('Failed to mark posted'); return }
      const data = await res.json() as { post?: SocialPost }
      const updatedPost = data.post
      if (!updatedPost) { setError('Failed to mark posted'); return }
      setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
    } finally {
      setMarkingPosted(false)
    }
  }

  async function handlePost() {
    if (!state?.isPostDay || posting) return
    setPosting(true)
    setError('')
    try {
      if (draftText !== state.post.draft_text) await handleSave()
      const res = await fetch(`/api/admin/social/${state.post.id}/schedule`, { method: 'POST' })
      if (!res.ok) {
        const body = await res.json().catch(() => ({})) as { error?: string; detail?: string }
        setError(body.error ?? 'Failed to post to LinkedIn')
        return
      }
      const data = await res.json() as { post?: SocialPost }
      const updatedPost = data.post
      if (!updatedPost) { setError('Failed to post to LinkedIn'); return }
      setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
    } finally {
      setPosting(false)
    }
  }

  async function handleCopyTemplate(index: number) {
    await navigator.clipboard.writeText(connectionTexts[index])
    setCopiedTemplate(index)
    setTimeout(() => setCopiedTemplate(null), 2000)
  }

  async function handleRegenerate() {
    if (!state?.isPostDay || regenerating) return
    setRegenerating(true)
    setError('')
    try {
      await fetch(`/api/admin/social/${state.post.id}`, { method: 'DELETE' }).catch(() => {})
      const res = await fetch(`/api/admin/social/today?regen=${Date.now()}`)
      if (!res.ok) { setError('Regeneration failed'); return }
      const data: TodayResponse = await res.json()
      setState(data)
      if (data.isPostDay) {
        setDraftText(data.post.draft_text)
        setNotesText(data.post.notes ?? '')
      }
    } finally {
      setRegenerating(false)
    }
  }

  async function handleToggleApproval() {
    if (!state?.isPostDay || togglingApproval) return
    setTogglingApproval(true)
    setError('')
    try {
      const nextApproved = !hasApprovedToken(state.post.notes)
      const nextNotes = setApprovedToken(state.post.notes, nextApproved)

      const res = await fetch(`/api/admin/social/${state.post.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ notes: nextNotes }),
      })

      if (!res.ok) {
        const data = await res.json().catch(() => ({})) as { error?: string }
        setError(data.error ?? 'Failed to update approval status')
        return
      }

      const data = await res.json() as { post?: SocialPost }
      const updated = data.post
      if (updated) {
        setState(prev => prev?.isPostDay ? { ...prev, post: updated } : prev)
        setNotesText(updated.notes ?? '')
      }
    } finally {
      setTogglingApproval(false)
    }
  }

  async function handleApprovedHandoff() {
    if (!state?.isPostDay || handoffSubmitting) return
    setHandoffSubmitting(true)
    setHandoffMessage('')
    setError('')

    try {
      const title = handoffTitle.trim() || `${formatDate(state.dateStr)} approved social article`
      const summary = handoffSummary.trim() || draftText.trim()
      if (!summary) {
        setError('Article summary is required for handoff')
        return
      }

      const variants = Math.max(1, Math.min(5, Math.floor(handoffVariants || 3)))
      const approvedNotes = setApprovedToken(state.post.notes, true)

      if (!hasApprovedToken(state.post.notes)) {
        const approvalRes = await fetch(`/api/admin/social/${state.post.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ notes: approvedNotes }),
        })
        if (approvalRes.ok) {
          const approvalData = await approvalRes.json() as { post?: SocialPost }
          const approvedPost = approvalData.post
          if (approvedPost) {
            setState(prev => prev?.isPostDay ? { ...prev, post: approvedPost } : prev)
            setNotesText(approvedPost.notes ?? '')
          }
        }
      }

      const res = await fetch('/api/admin/social/handoff-approved', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          approvalStatus: 'approved',
          pillar: handoffPillar,
          audience: handoffAudience.trim() || undefined,
          variantCount: variants,
          article: {
            title,
            url: handoffUrl.trim() || undefined,
            summary,
            keyTakeaways: summary
              .split(/[\n\.]/)
              .map(part => part.trim())
              .filter(Boolean)
              .slice(0, 2),
          },
        }),
      })

      const data = await res.json().catch(() => ({})) as {
        error?: string
        queued?: number
        posts?: Array<{ post_date: string }>
      }

      if (!res.ok) {
        setError(data.error ?? 'Approved handoff failed')
        return
      }

      const firstDate = data.posts?.[0]?.post_date
      setHandoffMessage(
        typeof data.queued === 'number'
          ? `Queued ${data.queued} approved posts${firstDate ? ` starting ${formatDate(firstDate)}` : ''}.`
          : 'Approved handoff queued successfully.'
      )
      await loadHandoffHistory()
    } finally {
      setHandoffSubmitting(false)
    }
  }

  function handleAddCalendarReminder() {
    const ics = buildCalendarReminderIcs(new Date())
    const blob = new Blob([ics], { type: 'text/calendar;charset=utf-8' })
    const url = URL.createObjectURL(blob)
    const anchor = document.createElement('a')
    anchor.href = url
    anchor.download = REVIEW_REMINDER_FILENAME
    anchor.click()
    URL.revokeObjectURL(url)
    setCalendarReminderSaved(true)
    window.setTimeout(() => setCalendarReminderSaved(false), 2200)
  }

  function handleAddGoogleCalendarReminder() {
    const url = buildGoogleCalendarReminderUrl(new Date())
    window.open(url, '_blank', 'noopener,noreferrer')
    setGoogleCalendarOpened(true)
    window.setTimeout(() => setGoogleCalendarOpened(false), 2200)
  }

  async function handleRunShortFormCouncilCheck() {
    if (!state?.isPostDay || councilChecking || !draftText.trim()) return
    setCouncilChecking(true)
    setError('')
    try {
      const res = await fetch(`/api/admin/social/${state.post.id}/council-check`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          draftText,
          emotionalAngle,
        }),
      })

      const data = await res.json().catch(() => ({})) as {
        error?: string
        result?: ShortFormCouncilCheck
        post?: SocialPost
      }

      if (!res.ok || !data.result) {
        setError(data.error ?? 'Failed to run council check')
        return
      }

      setCouncilCheck(data.result)
      const updatedPost = data.post
      if (updatedPost) {
        setState(prev => prev?.isPostDay ? { ...prev, post: updatedPost } : prev)
        setNotesText(updatedPost.notes ?? '')
      }
    } finally {
      setCouncilChecking(false)
    }
  }

  if (loading) {
    return (
      <div className="bg-white border border-slate-200 rounded p-8 flex items-center gap-2">
        <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block" />
        <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:150ms]" />
        <span className="w-1.5 h-1.5 rounded-full bg-slate-300 animate-pulse inline-block [animation-delay:300ms]" />
      </div>
    )
  }

  if (error) {
    return (
      <div className="bg-white border border-slate-200 rounded p-6">
        <p className="text-[13px] text-red-600 mb-3">{error}</p>
        <button
          type="button"
          onClick={() => { setError(''); load() }}
          className="text-[12px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 cursor-pointer bg-transparent transition-colors"
        >
          Try again
        </button>
      </div>
    )
  }

  if (!state) return null

  if (!state.isPostDay) {
    return (
      <div className="bg-white border border-slate-200 rounded p-8 text-center">
        <p className="text-[14px] font-semibold text-slate-900 mb-2">No post scheduled today.</p>
        <p className="text-[13px] text-slate-500">Posts go out every weekday with audience rotation.</p>
        {state.nextPostDays.length > 0 && (
          <p className="text-[12px] text-slate-400 mt-3">
            Next: {state.nextPostDays.map(d => formatDate(d)).join(', ')}
          </p>
        )}
      </div>
    )
  }

  const { post, pillarLabel, dateStr } = state
  const isApproved = hasApprovedToken(post.notes)
  const isDirty = draftText !== post.draft_text
  const isNotesDirty = notesText !== (post.notes ?? '')
  const busy = saving || savingNotes || markingPosted || posting || regenerating || togglingApproval || handoffSubmitting

  return (
    <div className="flex flex-col gap-4">

      {/* Date + pillar header */}
      <div className="bg-white border border-slate-200 rounded px-6 py-5 flex items-center justify-between gap-4">
        <div>
          <p className="text-[13px] font-semibold text-slate-900">{formatDate(dateStr)}</p>
          <div className="flex flex-wrap items-center gap-2 mt-1">
            <span className="text-[11px] font-bold tracking-[0.08em] uppercase bg-orange-50 text-orange-600 px-2 py-0.5 rounded">
              {pillarLabel}
            </span>
            {state.audienceLabel && (
              <span className="text-[11px] font-bold tracking-[0.08em] uppercase bg-blue-50 text-blue-700 px-2 py-0.5 rounded">
                {state.audienceLabel}
              </span>
            )}
            {state.recommendedTimeCt && !post.is_posted && (
              <span className="text-[11px] font-semibold bg-slate-100 text-slate-600 px-2 py-0.5 rounded">
                Target {state.recommendedTimeCt}
              </span>
            )}
            {post.is_posted && (
              <span className="text-[11px] font-bold bg-green-50 text-green-700 px-2 py-0.5 rounded">
                Posted {post.posted_at ? new Date(post.posted_at).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }) : ''}
              </span>
            )}
            <button
              type="button"
              onClick={handleToggleApproval}
              disabled={busy || post.is_posted}
              className={`text-[11px] font-bold px-2 py-0.5 rounded border transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer ${
                isApproved
                  ? 'bg-emerald-50 text-emerald-700 border-emerald-200 hover:border-emerald-400'
                  : 'bg-slate-100 text-slate-600 border-slate-200 hover:border-slate-400'
              }`}
            >
              {togglingApproval ? 'Saving…' : isApproved ? 'Approved' : 'Unapproved'}
            </button>
          </div>
        </div>
        <button
          type="button"
          onClick={handleRegenerate}
          disabled={busy}
          className="shrink-0 text-[12px] font-semibold text-slate-500 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-700 bg-transparent cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
        >
          {regenerating ? 'Generating…' : 'Regenerate'}
        </button>
      </div>

      {/* Draft editor */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-center justify-between mb-3">
          <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Post Draft</p>
          {isDirty && !saving && (
            <span className="text-[11px] text-amber-600 font-medium">Unsaved edits</span>
          )}
          {saving && (
            <span className="text-[11px] text-slate-400">Saving…</span>
          )}
        </div>
        <textarea
          value={draftText}
          onChange={e => setDraftText(e.target.value)}
          onBlur={isDirty ? handleSave : undefined}
          disabled={busy}
          rows={14}
          className="w-full text-[14px] text-slate-700 leading-relaxed border border-slate-200 rounded px-4 py-3 resize-none focus:outline-none focus:border-slate-400 font-[inherit] disabled:opacity-50"
          placeholder="Draft will appear here…"
        />
        <p className="mt-1.5 text-[11px] text-slate-300">{draftText.length} characters · Edits save on blur</p>
      </div>

      {/* Character count advisory */}
      {draftText.length > 3000 && (
        <div className="px-4 py-3 bg-amber-50 border border-amber-200 rounded text-[12px] text-amber-700">
          LinkedIn limits posts to 3,000 characters. This draft is {draftText.length} characters -- trim before posting.
        </div>
      )}

      {/* Short-form council helper */}
      <div id="content-checker" className="bg-white border border-slate-200 rounded p-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
          <div>
            <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Run Short-Form Council Check</p>
            <p className="text-[12px] text-slate-500 mt-1">Server-enforced council gate for posts under 1200 characters.</p>
          </div>
          <div className="flex items-center gap-2">
            <select
              value={emotionalAngle}
              onChange={e => setEmotionalAngle(e.target.value as EmotionalAngle)}
              className="text-[12px] text-slate-700 border border-slate-300 rounded px-2.5 py-2 bg-white focus:outline-none focus:border-slate-500"
              title="Primary emotional angle"
            >
              {ALLOWED_EMOTIONAL_ANGLES.map(angle => (
                <option key={angle} value={angle}>{angle.replace('_', ' ')}</option>
              ))}
            </select>
            <button
              type="button"
              onClick={handleRunShortFormCouncilCheck}
              disabled={!draftText.trim() || councilChecking}
              className="text-[12px] font-semibold text-slate-700 border border-slate-300 rounded px-4 py-2 hover:border-slate-500 hover:text-slate-900 disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer transition-colors bg-transparent"
            >
              {councilChecking ? 'Checking…' : 'Run Short-Form Council Check'}
            </button>
          </div>
        </div>

        {councilCheck && (
          <div className="mt-4 border-t border-slate-100 pt-4">
            <div className="flex flex-wrap items-center gap-2 mb-3">
              <span className="text-[12px] font-bold text-slate-900">Score {councilCheck.score}/100</span>
              <span className="text-[11px] font-semibold bg-slate-100 text-slate-600 px-2 py-0.5 rounded">{councilCheck.characterCount} chars</span>
              {councilCheck.emotionalAngle && (
                <span className="text-[11px] font-semibold bg-blue-50 text-blue-700 px-2 py-0.5 rounded">
                  Angle: {councilCheck.emotionalAngle.replace('_', ' ')}
                </span>
              )}
              <span className={`text-[11px] font-semibold px-2 py-0.5 rounded ${
                councilCheck.recommendation === 'publish'
                  ? 'bg-emerald-50 text-emerald-700'
                  : councilCheck.recommendation === 'revise'
                    ? 'bg-amber-50 text-amber-700'
                    : 'bg-red-50 text-red-700'
              }`}>
                {councilCheck.recommendation === 'publish' ? 'Publish' : councilCheck.recommendation === 'revise' ? 'Revise' : 'Rewrite opening'}
              </span>
              <span className={`text-[11px] font-semibold px-2 py-0.5 rounded ${councilCheck.councilPass ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>
                {councilCheck.councilPass ? 'Council pass' : 'Council fail'}
              </span>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 mb-3">
              <p className="text-[11px] text-slate-600">Hook: <span className="font-semibold text-slate-800">{councilCheck.categories.hook}/25</span></p>
              <p className="text-[11px] text-slate-600">Specificity: <span className="font-semibold text-slate-800">{councilCheck.categories.specificity}/20</span></p>
              <p className="text-[11px] text-slate-600">Credibility: <span className="font-semibold text-slate-800">{councilCheck.categories.credibility}/20</span></p>
              <p className="text-[11px] text-slate-600">Wit: <span className="font-semibold text-slate-800">{councilCheck.categories.wit}/15</span></p>
              <p className="text-[11px] text-slate-600">Compression: <span className="font-semibold text-slate-800">{councilCheck.categories.compression}/10</span></p>
              <p className="text-[11px] text-slate-600">CTA: <span className="font-semibold text-slate-800">{councilCheck.categories.cta}/10</span></p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mb-3">
              <p className="text-[11px] text-slate-600">Under 1200: <span className="font-semibold text-slate-800">{councilCheck.checks.under1200 ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">One core idea: <span className="font-semibold text-slate-800">{councilCheck.checks.oneCoreIdea ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">One CTA: <span className="font-semibold text-slate-800">{councilCheck.checks.oneCta ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">One humor line max: <span className="font-semibold text-slate-800">{councilCheck.checks.oneHumorLineMax ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Real detail present: <span className="font-semibold text-slate-800">{councilCheck.checks.realDetail ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Honest claim: <span className="font-semibold text-slate-800">{councilCheck.checks.honestClaim ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Angle selected: <span className="font-semibold text-slate-800">{councilCheck.checks.emotionalAnglePresent ? 'PASS' : 'FAIL'}</span></p>
              <p className="text-[11px] text-slate-600">Angle rotated: <span className="font-semibold text-slate-800">{councilCheck.checks.emotionalAngleRotation ? 'PASS' : 'FAIL'}</span></p>
            </div>

            <div>
              <p className="text-[11px] font-semibold text-slate-700 mb-1">Top fixes</p>
              <ul className="list-disc pl-5 text-[11px] text-slate-600 space-y-1">
                {councilCheck.topFixes.map(fix => (
                  <li key={fix}>{fix}</li>
                ))}
              </ul>
            </div>
          </div>
        )}
      </div>

      {/* Action buttons */}
      <div className="flex flex-col sm:flex-row gap-3">
        <button
          type="button"
          onClick={handlePost}
          disabled={busy || !draftText.trim() || post.is_posted}
          className="flex-1 bg-indigo-600 text-white text-[13px] font-semibold px-5 py-3 rounded cursor-pointer border-0 disabled:opacity-40 disabled:cursor-not-allowed transition-colors hover:bg-indigo-700"
        >
          {posting ? 'Posting…' : 'Post to LinkedIn'}
        </button>
        <button
          type="button"
          onClick={handleCopy}
          disabled={busy || !draftText.trim()}
          className="flex-1 bg-slate-900 text-white text-[13px] font-semibold px-5 py-3 rounded cursor-pointer border-0 disabled:opacity-40 disabled:cursor-not-allowed transition-colors hover:bg-slate-800"
        >
          {copied ? 'Copied!' : 'Copy to clipboard'}
        </button>
      </div>
      <div className="flex flex-col sm:flex-row gap-3">
        <a
          href={LINKEDIN_URL}
          target="_blank"
          rel="noopener noreferrer"
          className="flex-1 text-center text-[13px] font-semibold text-slate-700 border border-slate-200 rounded px-5 py-3 hover:border-slate-400 hover:text-slate-900 transition-colors"
        >
          Open LinkedIn
        </a>
        {!post.is_posted ? (
          <button
            type="button"
            onClick={handleMarkPosted}
            disabled={busy}
            className="flex-1 text-[13px] font-semibold text-green-700 border border-green-200 rounded px-5 py-3 hover:border-green-400 bg-green-50 cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
          >
            {markingPosted ? 'Saving…' : 'Mark posted (manual)'}
          </button>
        ) : (
          <div className="flex-1 text-center text-[13px] font-semibold text-green-700 border border-green-200 rounded px-5 py-3 bg-green-50">
            Posted
          </div>
        )}
      </div>

      {/* Approved article handoff */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-start justify-between gap-4 mb-4">
          <div>
            <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Handoff approved article</p>
            <p className="text-[12px] text-slate-500 mt-1">
              One click queues approved variants into upcoming open social slots.
            </p>
            <div className="mt-2 flex items-center gap-2">
              <button
                type="button"
                onClick={handleAddCalendarReminder}
                className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-2.5 py-1 hover:border-slate-400 hover:text-slate-800 cursor-pointer transition-colors"
              >
                Add calendar reminder (.ics)
              </button>
              <button
                type="button"
                onClick={handleAddGoogleCalendarReminder}
                className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-2.5 py-1 hover:border-slate-400 hover:text-slate-800 cursor-pointer transition-colors"
              >
                Add to Google Calendar
              </button>
              {calendarReminderSaved && (
                <span className="text-[11px] text-emerald-700">Downloaded</span>
              )}
              {googleCalendarOpened && (
                <span className="text-[11px] text-emerald-700">Opened</span>
              )}
            </div>
          </div>
          <span className={`text-[11px] font-bold px-2 py-0.5 rounded ${isApproved ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>
            {isApproved ? 'Current draft approved' : 'Current draft not approved'}
          </span>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Article title</label>
            <input
              value={handoffTitle}
              onChange={e => setHandoffTitle(e.target.value)}
              placeholder="Context rebuild and executive transitions"
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </div>
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Article URL (optional)</label>
            <input
              value={handoffUrl}
              onChange={e => setHandoffUrl(e.target.value)}
              placeholder="https://startingmonday.app/blog/..."
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </div>
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Pillar</label>
            <select
              value={handoffPillar}
              onChange={e => setHandoffPillar(e.target.value as (typeof PILLAR_OPTIONS)[number]['value'])}
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 bg-white focus:outline-none focus:border-slate-400"
              title="Select pillar"
            >
              {PILLAR_OPTIONS.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 mb-1">Audience (optional)</label>
            <input
              value={handoffAudience}
              onChange={e => setHandoffAudience(e.target.value)}
              placeholder="executive_coaches"
              className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </div>
        </div>

        <div className="mt-3">
          <label className="block text-[11px] font-semibold text-slate-500 mb-1">Article summary</label>
          <textarea
            value={handoffSummary}
            onChange={e => setHandoffSummary(e.target.value)}
            rows={4}
            className="w-full text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 resize-none focus:outline-none focus:border-slate-400"
            placeholder="Paste the approved article summary or leave the draft-derived default."
          />
        </div>

        <div className="mt-4 flex flex-col sm:flex-row gap-3 sm:items-end sm:justify-between">
          <label className="text-[11px] font-semibold text-slate-500">
            Variant count (1-5)
            <input
              type="number"
              min={1}
              max={5}
              value={handoffVariants}
              onChange={e => setHandoffVariants(Number(e.target.value || 3))}
              className="mt-1 block w-32 text-[13px] text-slate-700 border border-slate-200 rounded px-3 py-2 focus:outline-none focus:border-slate-400"
            />
          </label>

          <button
            type="button"
            onClick={handleApprovedHandoff}
            disabled={busy || !handoffSummary.trim()}
            className="text-[13px] font-semibold text-white bg-emerald-600 hover:bg-emerald-700 rounded px-5 py-2.5 disabled:opacity-40 disabled:cursor-not-allowed border-0 cursor-pointer transition-colors"
          >
            {handoffSubmitting ? 'Queueing…' : 'Handoff approved article'}
          </button>
        </div>

        {handoffMessage && (
          <p className="mt-3 text-[12px] text-emerald-700 bg-emerald-50 border border-emerald-200 rounded px-3 py-2">{handoffMessage}</p>
        )}

        <div className="mt-4 border-t border-slate-100 pt-4">
          <div className="flex items-center justify-between gap-3 mb-2">
            <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Recent handoff runs</p>
            {handoffHistoryLoading && <span className="text-[11px] text-slate-400">Loading…</span>}
          </div>

          {!handoffHistoryLoading && handoffHistory.length === 0 && (
            <p className="text-[12px] text-slate-500">No approved handoff runs yet.</p>
          )}

          {handoffHistory.length > 0 && (
            <div className="flex flex-col gap-2">
              {handoffHistory.slice(0, 5).map(run => (
                <div key={run.batchId} className="border border-slate-200 rounded p-3 bg-slate-50">
                  <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-1">
                    <p className="text-[12px] font-semibold text-slate-800 truncate">
                      {run.articleTitle || 'Approved handoff'}
                    </p>
                    <p className="text-[11px] text-slate-500">
                      {new Date(run.createdAt).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}
                    </p>
                  </div>
                  <p className="mt-1 text-[11px] text-slate-600">
                    Queued dates: {run.dates.map(date => formatDate(date)).join(', ')}
                  </p>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Connection outreach */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-center justify-between mb-4">
          <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">LinkedIn Connection Messages</p>
          <div className="flex gap-2">
            <a
              href={LINKEDIN_MESSAGING_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-800 transition-colors"
            >
              Open Messaging
            </a>
            <a
              href={LINKEDIN_MYNETWORK_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1.5 hover:border-slate-400 hover:text-slate-800 transition-colors"
            >
              My Network
            </a>
          </div>
        </div>
        <div className="flex flex-col gap-4">
          {CONNECTION_TEMPLATES.map((template, i) => (
            <div key={template.label} className="border border-slate-100 rounded p-4 bg-slate-50">
              <div className="flex items-center justify-between mb-2">
                <span className="text-[11px] font-bold text-slate-500 uppercase tracking-[0.07em]">{template.label}</span>
                <button
                  type="button"
                  onClick={() => handleCopyTemplate(i)}
                  className="text-[11px] font-semibold text-slate-600 border border-slate-200 rounded px-3 py-1 hover:border-slate-400 hover:text-slate-800 bg-white cursor-pointer transition-colors"
                >
                  {copiedTemplate === i ? 'Copied!' : 'Copy'}
                </button>
              </div>
              <textarea
                value={connectionTexts[i]}
                onChange={e => setConnectionTexts(prev => prev.map((t, j) => j === i ? e.target.value : t))}
                rows={3}
                title={template.label}
                placeholder="Edit connection message…"
                className="w-full text-[13px] text-slate-700 leading-relaxed border border-slate-200 rounded px-3 py-2 resize-none focus:outline-none focus:border-slate-400 font-[inherit] bg-white"
              />
              <p className="mt-1 text-[11px] text-slate-300">{connectionTexts[i].length} chars</p>
            </div>
          ))}
        </div>
      </div>

      {/* Notes */}
      <div className="bg-white border border-slate-200 rounded p-6">
        <div className="flex items-center justify-between mb-3">
          <p className="text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400">Notes (engagement, replies, reach)</p>
          {isNotesDirty && !savingNotes && (
            <span className="text-[11px] text-amber-600 font-medium">Unsaved</span>
          )}
          {savingNotes && (
            <span className="text-[11px] text-slate-400">Saving…</span>
          )}
        </div>
        <textarea
          value={notesText}
          onChange={e => setNotesText(e.target.value)}
          onBlur={isNotesDirty ? handleNotesSave : undefined}
          disabled={busy}
          rows={3}
          className="w-full text-[13px] text-slate-700 leading-relaxed border border-slate-200 rounded px-4 py-3 resize-none focus:outline-none focus:border-slate-400 font-[inherit] disabled:opacity-50"
          placeholder="Likes, comments, notable replies… saves on blur"
        />
      </div>

    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'

interface Scorecard {
  pipeline: {
    total_companies: number
    by_stage: {
      watching: number
      researching: number
      applied: number
      interviewing_or_offer: number
    }
    avg_fit_score: number
  }
  signals: {
    last_30_days: number
    avg_score: number
  }
  preparation: {
    briefs_last_30_days: number
    interviews_last_30_days: number
    interviews_by_outcome: {
      successful: number
      advancing: number
      rejected: number
    }
  }
  activity_health: {
    is_active: boolean
    last_signal_days: number
    last_brief_days: number
  }
  session_prep_snapshot: {
    signals_last_7_days: number
    briefs_last_7_days: number
    interviews_last_7_days: number
    active_pipeline_count: number
    overdue_actions: number
  }
  weekly_trends: Array<{
    week_start: string
    signals: number
    briefs: number
    interviews: number
  }>
}

interface NextAction {
  id: string
  action: string
  due_date: string
  status: string
  next_action_owner: string | null
  next_action_due_date: string | null
  next_action_status: string | null
  is_overdue: boolean
}

interface WeeklyReview {
  id: string
  week_start: string
  review_answers: Record<string, any>
  next_follow_up_id: string | null
  status: string
  completed_at: string | null
  created_at: string
  updated_at: string
}

interface WorkflowData {
  week_start: string
  current_review: WeeklyReview | null
  recent_reviews: WeeklyReview[]
  agenda_templates?: Array<{
    id: string
    label: string
    items: string[]
  }>
}

interface Company {
  id: string
  name: string
  stage: string
  fit_score: number
  notes?: string
}

interface Signal {
  id: string
  companies?: { name: string } | null
  signal_type: string
  signal_summary: string
  signal_date: string
  source_url?: string | null
}

interface Brief {
  id: string
  company_id: string
  companies?: { name: string } | null
  type: string
  output_text: string
  user_rating?: number | null
  created_at: string
}

export function CoachClientDataView({ clientId }: { clientId: string }) {
  const [scorecard, setScorecard] = useState<Scorecard | null>(null)
  const [companies, setCompanies] = useState<Company[]>([])
  const [signals, setSignals] = useState<Signal[]>([])
  const [briefs, setBriefs] = useState<Brief[]>([])
  const [workflow, setWorkflow] = useState<WorkflowData | null>(null)
  const [nextAction, setNextAction] = useState<NextAction | null>(null)
  const [actionDraft, setActionDraft] = useState({ action: '', owner: '', dueDate: '', status: 'open' })
  const [weeklyAnswers, setWeeklyAnswers] = useState({ signals: '', pipeline: '', brief: '', nextStep: '' })
  const [agendaTemplateId, setAgendaTemplateId] = useState('pipeline_reset')
  const [agendaItemsText, setAgendaItemsText] = useState('')
  const [sessionNotes, setSessionNotes] = useState({ wins: '', risks: '', decisions: '', freeform: '' })
  const [activeTab, setActiveTab] = useState('scorecard')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [savingAction, setSavingAction] = useState(false)
  const [savingReview, setSavingReview] = useState(false)
  const [actionMessage, setActionMessage] = useState<string | null>(null)
  const [reviewMessage, setReviewMessage] = useState<string | null>(null)
  const [extractingActions, setExtractingActions] = useState(false)

  const todayIso = new Date().toISOString().split('T')[0]

  useEffect(() => {
    async function loadData() {
      try {
        setLoading(true)
        const [scorecardRes, companiesRes, signalsRes, briefsRes, actionsRes, reviewRes] = await Promise.all([
          fetch(`/api/coach/client/${clientId}/scorecards`),
          fetch(`/api/coach/client/${clientId}/companies`),
          fetch(`/api/coach/client/${clientId}/signals`),
          fetch(`/api/coach/client/${clientId}/briefs`),
          fetch(`/api/coach/client/${clientId}/actions`),
          fetch(`/api/coach/client/${clientId}/weekly-review`),
        ])

        if (!scorecardRes.ok) throw new Error('Failed to load scorecard')
        if (!companiesRes.ok) throw new Error('Failed to load companies')
        if (!signalsRes.ok) throw new Error('Failed to load signals')
        if (!briefsRes.ok) throw new Error('Failed to load briefs')
        if (!actionsRes.ok) throw new Error('Failed to load next action')
        if (!reviewRes.ok) throw new Error('Failed to load weekly review')

        const scorecardData = await scorecardRes.json()
        const companiesData = await companiesRes.json()
        const signalsData = await signalsRes.json()
        const briefsData = await briefsRes.json()
        const actionsData = await actionsRes.json()
        const reviewData = await reviewRes.json()

        setScorecard(scorecardData.data)
        setCompanies(companiesData.data || [])
        setSignals(signalsData.data || [])
        setBriefs(briefsData.data || [])
        const currentAction = actionsData.data?.current_action ?? null
        setNextAction(currentAction)
        setActionDraft({
          action: currentAction?.action ?? '',
          owner: currentAction?.next_action_owner ?? '',
          dueDate: currentAction?.next_action_due_date ?? currentAction?.due_date ?? '',
          status: currentAction?.next_action_status ?? 'open',
        })

        const workflowData = reviewData.data as WorkflowData
        setWorkflow(workflowData)
        const answers = workflowData.current_review?.review_answers ?? {}
        setWeeklyAnswers({
          signals: answers.signals ?? '',
          pipeline: answers.pipeline ?? '',
          brief: answers.brief ?? '',
          nextStep: answers.nextStep ?? '',
        })
        setAgendaTemplateId(typeof answers.agenda_template === 'string' ? answers.agenda_template : 'pipeline_reset')
        setAgendaItemsText(Array.isArray(answers.agenda_items) ? answers.agenda_items.join('\n') : '')
        const notes = answers.session_notes && typeof answers.session_notes === 'object' ? answers.session_notes : {}
        setSessionNotes({
          wins: typeof notes.wins === 'string' ? notes.wins : '',
          risks: typeof notes.risks === 'string' ? notes.risks : '',
          decisions: typeof notes.decisions === 'string' ? notes.decisions : '',
          freeform: typeof notes.freeform === 'string' ? notes.freeform : '',
        })
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred')
      } finally {
        setLoading(false)
      }
    }

    loadData()
  }, [clientId])

  async function saveNextAction(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!actionDraft.action.trim() || !actionDraft.owner.trim() || !actionDraft.dueDate.trim()) return

    setSavingAction(true)
    setActionMessage(null)
    try {
      const response = await fetch(`/api/coach/client/${clientId}/actions`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          id: nextAction?.id,
          action: actionDraft.action.trim(),
          due_date: actionDraft.dueDate,
          next_action_owner: actionDraft.owner.trim(),
          next_action_due_date: actionDraft.dueDate,
          next_action_status: actionDraft.status,
          status: actionDraft.status,
        }),
      })

      const json = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(json.error ?? 'Failed to save next action')

      const savedAction = json.data
      setNextAction(savedAction)
      setActionDraft({
        action: savedAction.action ?? '',
        owner: savedAction.next_action_owner ?? '',
        dueDate: savedAction.next_action_due_date ?? savedAction.due_date ?? '',
        status: savedAction.next_action_status ?? 'open',
      })
      setActionMessage('Next action saved.')
    } catch (err) {
      setActionMessage(err instanceof Error ? err.message : 'Could not save next action')
    } finally {
      setSavingAction(false)
    }
  }

  async function saveWeeklyReview(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!actionDraft.action.trim() || !actionDraft.owner.trim() || !actionDraft.dueDate.trim()) {
      setReviewMessage('Add a next action owner and due date before saving the review.')
      return
    }

    setSavingReview(true)
    setReviewMessage(null)
    try {
      const response = await fetch(`/api/coach/client/${clientId}/weekly-review`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          week_start: workflow?.week_start,
          answers: {
            signals: weeklyAnswers.signals.trim(),
            pipeline: weeklyAnswers.pipeline.trim(),
            brief: weeklyAnswers.brief.trim(),
            nextStep: weeklyAnswers.nextStep.trim(),
          },
          next_action: {
            action: actionDraft.action.trim(),
            owner: actionDraft.owner.trim(),
            due_date: actionDraft.dueDate,
            status: actionDraft.status,
          },
          agenda_template: agendaTemplateId,
          agenda_items: agendaItemsText
            .split('\n')
            .map((item) => item.trim())
            .filter(Boolean)
            .slice(0, 8),
          session_notes: {
            wins: sessionNotes.wins.trim(),
            risks: sessionNotes.risks.trim(),
            decisions: sessionNotes.decisions.trim(),
            freeform: sessionNotes.freeform.trim(),
          },
        }),
      })

      const json = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(json.error ?? 'Failed to save weekly review')

      const savedAction = json.data?.next_action ?? null
      const savedReview = json.data?.weekly_review ?? null
      if (savedAction) {
        setNextAction(savedAction)
        setActionDraft({
          action: savedAction.action ?? '',
          owner: savedAction.next_action_owner ?? '',
          dueDate: savedAction.next_action_due_date ?? savedAction.due_date ?? '',
          status: savedAction.next_action_status ?? 'open',
        })
      }
      if (savedReview) {
        setWorkflow((current) => current ? { ...current, current_review: savedReview, recent_reviews: [savedReview, ...(current.recent_reviews ?? []).filter((review) => review.id !== savedReview.id)].slice(0, 4) } : { week_start: savedReview.week_start, current_review: savedReview, recent_reviews: [savedReview] })
      }
      setReviewMessage('Weekly review and session artifact saved.')
    } catch (err) {
      setReviewMessage(err instanceof Error ? err.message : 'Could not save weekly review')
    } finally {
      setSavingReview(false)
    }
  }

  async function extractActionsFromSession() {
    if (extractingActions) return
    setExtractingActions(true)
    setActionMessage(null)
    try {
      const response = await fetch(`/api/coach/client/${clientId}/actions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          owner: actionDraft.owner.trim(),
          due_date: actionDraft.dueDate,
        }),
      })

      const json = await response.json().catch(() => ({}))
      if (!response.ok) throw new Error(json.error ?? 'Failed to extract actions')

      const extracted = Number(json.data?.extracted ?? 0)
      setActionMessage(extracted > 0 ? `Extracted ${extracted} action${extracted === 1 ? '' : 's'} from session notes.` : 'No actionable items found in latest notes.')
    } catch (err) {
      setActionMessage(err instanceof Error ? err.message : 'Could not extract actions')
    } finally {
      setExtractingActions(false)
    }
  }

  if (loading) {
    return <div className="p-6 text-center">Loading client data...</div>
  }

  if (error) {
    return <div className="p-6 text-red-600">Error: {error}</div>
  }

  if (!scorecard) {
    return <div className="p-6 text-center">No data available</div>
  }

  const actionDueDate = nextAction?.next_action_due_date ?? nextAction?.due_date ?? actionDraft.dueDate
  const actionOwner = nextAction?.next_action_owner ?? actionDraft.owner
  const actionStatus = nextAction?.next_action_status ?? actionDraft.status
  const actionIsOverdue = Boolean(actionDueDate && actionStatus !== 'completed' && actionDueDate < todayIso)
  const recentReviews = workflow?.recent_reviews ?? []
  const agendaTemplates = workflow?.agenda_templates ?? []

  return (
    <div className="space-y-6">
      {/* Workflow Snapshot */}
      <div className="border border-slate-200 rounded-lg p-4 bg-white">
        <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-3">
          Session Prep Snapshot (last 7 days)
        </p>
        <div className="grid grid-cols-2 md:grid-cols-6 gap-3">
          <div className="rounded border border-slate-200 p-3 bg-slate-50">
            <p className="text-[11px] text-slate-500">Signals</p>
            <p className="text-[18px] font-bold text-slate-900">{scorecard.session_prep_snapshot.signals_last_7_days}</p>
          </div>
          <div className="rounded border border-slate-200 p-3 bg-slate-50">
            <p className="text-[11px] text-slate-500">Briefs</p>
            <p className="text-[18px] font-bold text-slate-900">{scorecard.session_prep_snapshot.briefs_last_7_days}</p>
          </div>
          <div className="rounded border border-slate-200 p-3 bg-slate-50">
            <p className="text-[11px] text-slate-500">Interviews</p>
            <p className="text-[18px] font-bold text-slate-900">{scorecard.session_prep_snapshot.interviews_last_7_days}</p>
          </div>
          <div className="rounded border border-slate-200 p-3 bg-slate-50">
            <p className="text-[11px] text-slate-500">Active pipeline</p>
            <p className="text-[18px] font-bold text-slate-900">{scorecard.session_prep_snapshot.active_pipeline_count}</p>
          </div>
          <div className="rounded border border-slate-200 p-3 bg-slate-50">
            <p className="text-[11px] text-slate-500">Overdue actions</p>
            <p className={`text-[18px] font-bold ${scorecard.session_prep_snapshot.overdue_actions > 0 ? 'text-red-600' : 'text-slate-900'}`}>
              {scorecard.session_prep_snapshot.overdue_actions}
            </p>
          </div>
          <div className={`rounded border p-3 ${actionIsOverdue ? 'border-red-200 bg-red-50' : 'border-slate-200 bg-slate-50'}`}>
            <p className="text-[11px] text-slate-500">Next action</p>
            <p className="text-[13px] font-semibold text-slate-900 line-clamp-2">{nextAction?.action ?? actionDraft.action ?? 'Unassigned'}</p>
            <p className="text-[11px] text-slate-500 mt-1">{actionOwner ? `Owner: ${actionOwner}` : 'Owner: unassigned'}</p>
            <p className={`text-[11px] mt-0.5 ${actionIsOverdue ? 'text-red-700' : 'text-slate-500'}`}>
              Due {actionDueDate || 'TBD'}{actionStatus ? ` · ${actionStatus}` : ''}
            </p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
        <div className="border border-slate-200 rounded-lg p-5 bg-white">
          <div className="flex items-start justify-between gap-4 mb-4">
            <div>
              <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-1">Next action editor</p>
              <h3 className="text-[16px] font-semibold text-slate-900">Manager-style ownership and due date</h3>
            </div>
            {actionIsOverdue && (
              <span className="text-[11px] font-semibold text-red-700 bg-red-50 px-2 py-1 rounded-full">Overdue</span>
            )}
          </div>
          <form onSubmit={saveNextAction} className="space-y-3">
            <div>
              <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Action</label>
              <input
                value={actionDraft.action}
                onChange={(event) => setActionDraft((current) => ({ ...current, action: event.target.value }))}
                placeholder="Send updated prep brief and confirm interview date"
                className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400"
              />
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Owner</label>
                <input
                  aria-label="Next action owner"
                  value={actionDraft.owner}
                  onChange={(event) => setActionDraft((current) => ({ ...current, owner: event.target.value }))}
                  placeholder="Coach or client"
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Due date</label>
                <input
                  aria-label="Next action due date"
                  value={actionDraft.dueDate}
                  onChange={(event) => setActionDraft((current) => ({ ...current, dueDate: event.target.value }))}
                  type="date"
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Status</label>
                <select
                  aria-label="Next action status"
                  value={actionDraft.status}
                  onChange={(event) => setActionDraft((current) => ({ ...current, status: event.target.value }))}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] bg-white focus:outline-none focus:border-slate-400"
                >
                  <option value="open">Open</option>
                  <option value="in_progress">In progress</option>
                  <option value="completed">Completed</option>
                </select>
              </div>
            </div>
            <button
              type="submit"
              disabled={savingAction || !actionDraft.action.trim() || !actionDraft.owner.trim() || !actionDraft.dueDate.trim()}
              className="bg-slate-900 hover:bg-slate-700 disabled:opacity-40 text-white text-[13px] font-semibold px-4 py-2 rounded transition-colors cursor-pointer border-0"
            >
              {savingAction ? 'Saving...' : 'Save next action'}
            </button>
            {actionMessage && (
              <p className={`text-[12px] ${actionMessage.includes('saved') ? 'text-green-700' : 'text-red-600'}`}>{actionMessage}</p>
            )}
          </form>
        </div>

        <div className="border border-slate-200 rounded-lg p-5 bg-white">
          <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-1">Weekly review rhythm</p>
          <h3 className="text-[16px] font-semibold text-slate-900 mb-3">Repeatable in-app workflow</h3>
          <p className="text-[13px] text-slate-600 leading-relaxed mb-4">
            Save the current week, then carry the next action forward into the following review.
          </p>
          <div className="space-y-3 text-[13px] text-slate-700">
            <div className="flex items-center justify-between gap-4">
              <span className="text-slate-500">Current week</span>
              <span className="font-semibold">{workflow?.week_start ?? 'This week'}</span>
            </div>
            <div className="flex items-center justify-between gap-4">
              <span className="text-slate-500">Status</span>
              <span className="font-semibold text-green-700">{workflow?.current_review ? 'Saved' : 'Not saved yet'}</span>
            </div>
            <div className="flex items-center justify-between gap-4">
              <span className="text-slate-500">Recent reviews</span>
              <span className="font-semibold tabular-nums">{recentReviews.length}</span>
            </div>
          </div>
          <div className="mt-4 border-t border-slate-100 pt-4 space-y-2">
            {recentReviews.length > 0 ? (
              recentReviews.map((review) => (
                <div key={review.id} className="flex items-center justify-between gap-3 text-[12px]">
                  <span className="text-slate-600">Week of {review.week_start}</span>
                  <span className="font-semibold text-slate-900">{review.status}</span>
                </div>
              ))
            ) : (
              <p className="text-[12px] text-slate-400">No weekly reviews saved yet.</p>
            )}
          </div>
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-slate-200">
        <div className="flex gap-4">
          {[
            { id: 'scorecard', label: 'Scorecard' },
            { id: 'review', label: 'Weekly Review' },
            { id: 'trends', label: 'Weekly Trends' },
            { id: 'pipeline', label: 'Pipeline' },
            { id: 'signals', label: 'Signals' },
            { id: 'briefs', label: 'Briefs' },
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                activeTab === tab.id
                  ? 'border-orange-500 text-orange-600'
                  : 'border-transparent text-slate-600 hover:text-slate-900'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Scorecard Tab */}
      {activeTab === 'scorecard' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="border border-slate-200 rounded-lg p-6 bg-white">
            <h3 className="text-sm font-semibold text-slate-900 mb-4">Pipeline Health</h3>
            <div className="space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Total Companies</span>
                <span className="text-lg font-bold text-slate-900">
                  {scorecard.pipeline.total_companies}
                </span>
              </div>
              <div className="grid grid-cols-4 gap-2">
                {Object.entries(scorecard.pipeline.by_stage).map(([stage, count]) => (
                  <div key={stage} className="text-center">
                    <div className="text-xs text-slate-500 capitalize">
                      {stage.replace('_', ' ')}
                    </div>
                    <div className="text-lg font-bold text-slate-900">{count}</div>
                  </div>
                ))}
              </div>
              <div className="flex justify-between items-center pt-2 border-t border-slate-100">
                <span className="text-sm text-slate-600">Avg Fit Score</span>
                <span className="text-lg font-bold text-orange-600">
                  {scorecard.pipeline.avg_fit_score}%
                </span>
              </div>
            </div>
          </div>

          <div className="border border-slate-200 rounded-lg p-6 bg-white">
            <h3 className="text-sm font-semibold text-slate-900 mb-4">Activity Health</h3>
            <div className="space-y-3">
              <div>
                <div className="flex items-center justify-between mb-1">
                  <span className="text-sm text-slate-600">Status</span>
                  <span
                    className={`text-sm font-semibold ${
                      scorecard.activity_health.is_active
                        ? 'text-green-600'
                        : 'text-slate-400'
                    }`}
                  >
                    {scorecard.activity_health.is_active ? 'Active' : 'Inactive'}
                  </span>
                </div>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Last Signal</span>
                <span className="text-sm font-medium text-slate-900">
                  {scorecard.activity_health.last_signal_days >= 999
                    ? 'None'
                    : `${scorecard.activity_health.last_signal_days}d ago`}
                </span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Last Brief</span>
                <span className="text-sm font-medium text-slate-900">
                  {scorecard.activity_health.last_brief_days >= 999
                    ? 'None'
                    : `${scorecard.activity_health.last_brief_days}d ago`}
                </span>
              </div>
            </div>
          </div>

          <div className="border border-slate-200 rounded-lg p-6 bg-white">
            <h3 className="text-sm font-semibold text-slate-900 mb-4">Signal Activity</h3>
            <div className="space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Last 30 Days</span>
                <span className="text-lg font-bold text-slate-900">
                  {scorecard.signals.last_30_days}
                </span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Avg Score</span>
                <span className="text-lg font-bold text-orange-600">
                  {scorecard.signals.avg_score}
                </span>
              </div>
            </div>
          </div>

          <div className="border border-slate-200 rounded-lg p-6 bg-white">
            <h3 className="text-sm font-semibold text-slate-900 mb-4">Interview Outcomes</h3>
            <div className="space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Successful</span>
                <span className="text-lg font-bold text-green-600">
                  {scorecard.preparation.interviews_by_outcome.successful}
                </span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Advancing</span>
                <span className="text-lg font-bold text-blue-600">
                  {scorecard.preparation.interviews_by_outcome.advancing}
                </span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-slate-600">Rejected</span>
                <span className="text-lg font-bold text-red-600">
                  {scorecard.preparation.interviews_by_outcome.rejected}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Weekly Review Tab */}
      {activeTab === 'review' && (
        <form onSubmit={saveWeeklyReview} className="space-y-4 border border-slate-200 rounded-lg p-5 bg-white">
          <div>
            <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-1">Weekly review</p>
            <h3 className="text-[16px] font-semibold text-slate-900">Turn the template into a recurring workflow</h3>
            <p className="text-[13px] text-slate-500 mt-1">Week of {workflow?.week_start ?? 'this week'}</p>
          </div>

          <div className="border border-slate-200 rounded-lg p-4 bg-slate-50 space-y-3">
            <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500">Session agenda template</p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Template</label>
                <select
                  value={agendaTemplateId}
                  onChange={(event) => setAgendaTemplateId(event.target.value)}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] bg-white focus:outline-none focus:border-slate-400"
                >
                  {agendaTemplates.map((template) => (
                    <option key={template.id} value={template.id}>{template.label}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Agenda items (editable)</label>
                <textarea
                  value={agendaItemsText}
                  onChange={(event) => setAgendaItemsText(event.target.value)}
                  rows={4}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                  placeholder="One item per line"
                />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">What changed in signals?</label>
              <textarea
                value={weeklyAnswers.signals}
                onChange={(event) => setWeeklyAnswers((current) => ({ ...current, signals: event.target.value }))}
                rows={3}
                className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                placeholder="New hires, funding, promotions, product launches, or other moves"
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Which companies moved or stalled?</label>
              <textarea
                value={weeklyAnswers.pipeline}
                onChange={(event) => setWeeklyAnswers((current) => ({ ...current, pipeline: event.target.value }))}
                rows={3}
                className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                placeholder="Pipeline movement, blockers, interview progress, or delays"
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Which prep brief matters this week?</label>
              <textarea
                value={weeklyAnswers.brief}
                onChange={(event) => setWeeklyAnswers((current) => ({ ...current, brief: event.target.value }))}
                rows={3}
                className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                placeholder="The most important brief, interview, or conversation to prepare"
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">What is the one action before next session?</label>
              <textarea
                value={weeklyAnswers.nextStep}
                onChange={(event) => setWeeklyAnswers((current) => ({ ...current, nextStep: event.target.value }))}
                rows={3}
                className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                placeholder="One concrete step to finish before the next weekly check-in"
              />
            </div>
          </div>

          <div className="border border-slate-200 rounded-lg p-4 bg-slate-50">
            <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-3">Session note capture</p>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Wins</label>
                <textarea
                  value={sessionNotes.wins}
                  onChange={(event) => setSessionNotes((current) => ({ ...current, wins: event.target.value }))}
                  rows={3}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                  placeholder="What improved this week"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Risks</label>
                <textarea
                  value={sessionNotes.risks}
                  onChange={(event) => setSessionNotes((current) => ({ ...current, risks: event.target.value }))}
                  rows={3}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                  placeholder="What is at risk"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Decisions</label>
                <textarea
                  value={sessionNotes.decisions}
                  onChange={(event) => setSessionNotes((current) => ({ ...current, decisions: event.target.value }))}
                  rows={3}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                  placeholder="Decisions made in session"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Freeform notes</label>
                <textarea
                  value={sessionNotes.freeform}
                  onChange={(event) => setSessionNotes((current) => ({ ...current, freeform: event.target.value }))}
                  rows={3}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400 resize-none"
                  placeholder="Context and narrative from the session"
                />
              </div>
            </div>
          </div>

          <div className="border border-slate-200 rounded-lg p-4 bg-slate-50 space-y-3">
            <div className="flex items-center justify-between gap-4">
              <div>
                <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500">Next action required</p>
                <p className="text-[12px] text-slate-500">The review cannot be saved without an owner and due date.</p>
              </div>
              {actionIsOverdue && <span className="text-[11px] font-semibold text-red-700 bg-red-50 px-2 py-1 rounded-full">Overdue</span>}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Action</label>
                <input
                    aria-label="Weekly review next action"
                  value={actionDraft.action}
                  onChange={(event) => setActionDraft((current) => ({ ...current, action: event.target.value }))}
                  placeholder="Confirm interview prep session"
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Owner</label>
                <input
                    aria-label="Weekly review next action owner"
                  value={actionDraft.owner}
                  onChange={(event) => setActionDraft((current) => ({ ...current, owner: event.target.value }))}
                  placeholder="Client or coach"
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400"
                />
              </div>
              <div>
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Due date</label>
                <input
                    aria-label="Weekly review next action due date"
                  value={actionDraft.dueDate}
                  onChange={(event) => setActionDraft((current) => ({ ...current, dueDate: event.target.value }))}
                  type="date"
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] focus:outline-none focus:border-slate-400"
                />
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="flex-1 max-w-[220px]">
                <label className="block text-[10px] font-bold tracking-[0.1em] uppercase text-slate-400 mb-1">Next action status</label>
                <select
                  aria-label="Weekly review next action status"
                  value={actionDraft.status}
                  onChange={(event) => setActionDraft((current) => ({ ...current, status: event.target.value }))}
                  className="w-full border border-slate-200 rounded px-3 py-2 text-[13px] bg-white focus:outline-none focus:border-slate-400"
                >
                  <option value="open">Open</option>
                  <option value="in_progress">In progress</option>
                  <option value="completed">Completed</option>
                </select>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            <button
              type="submit"
              disabled={savingReview || !actionDraft.action.trim() || !actionDraft.owner.trim() || !actionDraft.dueDate.trim()}
              className="bg-orange-600 hover:bg-orange-500 disabled:opacity-40 text-white text-[13px] font-semibold px-4 py-2 rounded transition-colors cursor-pointer border-0"
            >
              {savingReview ? 'Saving review...' : 'Save weekly review'}
            </button>
            <button
              type="button"
              onClick={extractActionsFromSession}
              disabled={extractingActions}
              className="bg-white hover:bg-slate-50 text-[13px] font-semibold px-4 py-2 rounded border border-slate-200 text-slate-700 disabled:opacity-40"
            >
              {extractingActions ? 'Extracting...' : 'Extract actions from notes'}
            </button>
          </div>

          {reviewMessage && (
            <p className={`text-[12px] ${reviewMessage.includes('saved') ? 'text-green-700' : 'text-red-600'}`}>{reviewMessage}</p>
          )}

          {recentReviews.length > 0 && (
            <div className="border-t border-slate-100 pt-4">
              <p className="text-[11px] font-bold tracking-[0.1em] uppercase text-slate-500 mb-3">Recent reviews</p>
              <div className="space-y-3">
                {recentReviews.map((review) => (
                  <div key={review.id} className="border border-slate-200 rounded p-3">
                    <div className="flex items-center justify-between gap-3 mb-2">
                      <p className="text-[12px] font-semibold text-slate-900">Week of {review.week_start}</p>
                      <span className="text-[11px] text-slate-500">{review.status}</span>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-2 text-[12px] text-slate-600">
                      <p><span className="font-semibold text-slate-700">Signals:</span> {review.review_answers.signals ?? '—'}</p>
                      <p><span className="font-semibold text-slate-700">Pipeline:</span> {review.review_answers.pipeline ?? '—'}</p>
                      <p><span className="font-semibold text-slate-700">Brief:</span> {review.review_answers.brief ?? '—'}</p>
                      <p><span className="font-semibold text-slate-700">Next step:</span> {review.review_answers.nextStep ?? '—'}</p>
                      <p><span className="font-semibold text-slate-700">Agenda:</span> {review.review_answers.agenda_template ?? '—'}</p>
                      <p><span className="font-semibold text-slate-700">Session notes:</span> {review.review_answers.session_notes?.freeform ?? '—'}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </form>
      )}

      {/* Weekly Trends Tab */}
      {activeTab === 'trends' && (
        <div className="border border-slate-200 rounded-lg p-5 bg-white">
          <h3 className="text-sm font-semibold text-slate-900 mb-4">Weekly Progress Markers</h3>
          <div className="overflow-x-auto border border-slate-200 rounded-lg">
            <table className="w-full">
              <thead>
                <tr className="border-b border-slate-100 bg-slate-50">
                  <th className="text-left text-[11px] font-semibold text-slate-600 px-4 py-2">Week</th>
                  <th className="text-right text-[11px] font-semibold text-slate-600 px-4 py-2">Signals</th>
                  <th className="text-right text-[11px] font-semibold text-slate-600 px-4 py-2">Briefs</th>
                  <th className="text-right text-[11px] font-semibold text-slate-600 px-4 py-2">Interviews</th>
                </tr>
              </thead>
              <tbody>
                {scorecard.weekly_trends.map((week) => (
                  <tr key={week.week_start} className="border-b border-slate-100 last:border-0">
                    <td className="px-4 py-2 text-[12px] text-slate-700">Week of {week.week_start}</td>
                    <td className="px-4 py-2 text-[12px] text-right font-semibold text-slate-900 tabular-nums">{week.signals}</td>
                    <td className="px-4 py-2 text-[12px] text-right font-semibold text-slate-900 tabular-nums">{week.briefs}</td>
                    <td className="px-4 py-2 text-[12px] text-right font-semibold text-slate-900 tabular-nums">{week.interviews}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Pipeline Tab */}
      {activeTab === 'pipeline' && (
        <div className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {companies.map((company) => (
              <div key={company.id} className="border border-slate-200 rounded-lg p-4 bg-white">
                <h4 className="font-semibold text-slate-900">{company.name}</h4>
                <div className="flex justify-between items-center mt-2">
                  <span className="text-sm text-slate-600 capitalize">{company.stage}</span>
                  <span className="text-sm font-bold text-orange-600">{company.fit_score}%</span>
                </div>
                {company.notes && (
                  <p className="text-sm text-slate-500 mt-2 line-clamp-2">{company.notes}</p>
                )}
              </div>
            ))}
          </div>
          {companies.length === 0 && (
            <div className="text-center text-slate-500 p-8">No companies in pipeline</div>
          )}
        </div>
      )}

      {/* Signals Tab */}
      {activeTab === 'signals' && (
        <div className="space-y-4">
          {signals.slice(0, 20).map((signal) => (
            <div key={signal.id} className="border border-slate-200 rounded-lg p-4 bg-white">
              <div className="flex justify-between items-start mb-2">
                <h4 className="font-semibold text-slate-900">
                  {(signal.companies?.name ?? 'Company')} · {signal.signal_type.replace('_', ' ')}
                </h4>
                <span className="text-xs font-bold text-orange-600 bg-orange-50 px-2 py-1 rounded capitalize">
                  {signal.signal_type.replace('_', ' ')}
                </span>
              </div>
              <p className="text-sm text-slate-600 mb-2">{signal.signal_summary}</p>
              <p className="text-xs text-slate-500">
                {new Date(signal.signal_date).toLocaleDateString()}
              </p>
              {signal.source_url && (
                <a
                  href={signal.source_url}
                  target="_blank"
                  rel="noreferrer"
                  className="text-xs text-slate-500 hover:text-slate-700 underline underline-offset-2"
                >
                  Open source
                </a>
              )}
            </div>
          ))}
          {signals.length === 0 && (
            <div className="text-center text-slate-500 p-8">No signals detected</div>
          )}
        </div>
      )}

      {/* Briefs Tab */}
      {activeTab === 'briefs' && (
        <div className="space-y-4">
          {briefs.slice(0, 20).map((brief) => (
            <div key={brief.id} className="border border-slate-200 rounded-lg p-4 bg-white">
              <div className="flex justify-between items-start">
                <div>
                  <h4 className="font-semibold text-slate-900">
                    {(brief.companies?.name ?? 'General')} · {brief.type}
                  </h4>
                  <p className="text-sm text-slate-600 mt-1 line-clamp-3">{brief.output_text}</p>
                </div>
              </div>
              {brief.user_rating !== null && brief.user_rating !== undefined && (
                <p className="text-xs text-slate-500 mt-2">Rating: {brief.user_rating > 0 ? 'positive' : 'negative'}</p>
              )}
              <p className="text-xs text-slate-500 mt-3">
                {new Date(brief.created_at).toLocaleDateString()}
              </p>
            </div>
          ))}
          {briefs.length === 0 && (
            <div className="text-center text-slate-500 p-8">No briefs created</div>
          )}
        </div>
      )}
    </div>
  )
}

