` : ''}JOB SCAN DATA
${scanSection}
${signalSection ? `\nCOMPANY SIGNALS (recent news events)\n${signalSection}` : ''}
${focusBrief ? `\nCOMPANY FOCUS BRIEF (inferred from signals)\n${focusBrief}` : ''}
