    if ('email_text' in row) row.email_text = body
    if ('email_body_core' in row) row.email_body_core = body
    updated++
  }
  await writeFile(full, toCsv(headers, rows), 'utf8')
  return updated
}

async function updateOutplacementFile(relPath) {
